use std::io;

static ALPHABET: &str = "ABCDEFGHIJKLMNOPQRSTUVWXYZ";

fn find_number_of_ops(length_of_string: usize, s: String) -> usize {
    let mut number_of_ops = vec![];
    for i in 0..length_of_string-3 {
        let substring = &s[i..i+4];
        let mut ops = 0;
        for (index_of_letter_in_substring, letter) in substring.chars().enumerate() {
            if letter != "ACTG".chars().nth(index_of_letter_in_substring).unwrap() {
                // number of operations is not zero for this letter
                let position_of_letter_in_alphabet = ALPHABET.find(letter).unwrap();
                let position_of_target_in_alphabet = ALPHABET.find("ACTG".chars().nth(index_of_letter_in_substring).unwrap()).unwrap();
                let x: usize = (position_of_letter_in_alphabet as isize - position_of_target_in_alphabet as isize).abs() as usize;
                let y: usize = 26 - (position_of_target_in_alphabet as isize - position_of_letter_in_alphabet as isize).abs() as usize;
                ops += if x < y {x} else {y};
            }
            if index_of_letter_in_substring == 3 {
                number_of_ops.push(ops);
            }
        }
    }
    let mut minimum_ops = number_of_ops[0];
    for ops in number_of_ops.iter() {
        if ops < &minimum_ops {
            minimum_ops = *ops;
        }
    }
    minimum_ops
}

fn main() {
    let mut length_of_string = String::new();
    io::stdin().read_line(&mut length_of_string).unwrap();
    let length_of_string: usize = length_of_string.trim().parse().unwrap();
    let mut s = String::new();
    io::stdin().read_line(&mut s).unwrap();
    println!("{}", find_number_of_ops(length_of_string, s.trim().to_string()));
}
